#!/usr/bin/env bash
# GENERATED by `ggen sync` from .specify/templates/verify/verify_evidence_sh.sh.tera
# (ggen.toml's own declarative-rules mirror of packs/ggen-verify-pack's
# templates/verify_evidence_sh.tmpl -- see that file's header for the schema
# note on why this repo needs its own copy). Evidence emitter for the
# self-hosted verification loop: runs every ver:RequiredCheck admitted from
# the union graph (name + ver:checkCommand are ontology facts, not
# hand-maintained here) and records the REAL exit codes as ver:Check facts
# in evidence/ontology.ttl -- the local `verify-evidence` mini-pack wired as
# an [ontology] import below.
#
# This script ALWAYS exits 0: it records reality, it does not judge it.
# Judgment belongs to packs/ggen-verify-pack/gates/010,020*.rq at the next
# `ggen sync run` -- red or missing evidence there is a refusal. That split
# (emit facts / gate facts) is the point.
set -uo pipefail

cd "$(dirname "$0")/.."
mkdir -p evidence

RECORDED_AT="$(date -u +%Y-%m-%dT%H:%M:%SZ)"

GRAPH_HASH="unsynced"
if [ -f .ggen-v2/receipt.json ]; then
  GRAPH_HASH="$(python3 -c 'import json;print(json.load(open(".ggen-v2/receipt.json"))["payload"]["graph_hash"])' 2>/dev/null || echo unsynced)"
fi

CHECK_NAMES=(); CHECK_CODES=(); CHECK_TOOLS=(); CHECK_SUMMARIES=()
run_check() { # name, command-string (run via bash -c from the repo root)
  local name="$1" cmd="$2"
  local log="${TMPDIR:-/tmp}/verify-evidence-$name-$$.log"
  bash -c "$cmd" >"$log" 2>&1
  local code=$?
  CHECK_NAMES+=("$name")
  CHECK_CODES+=("$code")
  CHECK_TOOLS+=("$cmd")
  CHECK_SUMMARIES+=("$(tail -1 "$log" | tr '"' "'" | cut -c1-200)")
  rm -f "$log"
}

run_check 'build' 'cargo build --workspace'
run_check 'byte-identity' 'bash scripts/checks/byte-identity.sh'
run_check 'clippy-reference-gate' 'cargo clippy --workspace --all-targets -- -D clippy::correctness -D clippy::suspicious -D clippy::perf'
run_check 'test-workspace' 'cargo test --workspace'

{
  echo "# GENERATED by scripts/verify-evidence.sh at $RECORDED_AT -- do not edit."
  echo "# Real exit codes from real command runs; gated by ggen-verify-pack."
  echo "@prefix ver: <http://seanchatmangpt.github.io/packs/ggen-verify#> ."
  echo
  for i in "${!CHECK_NAMES[@]}"; do
    n="${CHECK_NAMES[$i]}"
    echo "ver:check-$n a ver:Check ;"
    echo "    ver:name \"$n\" ;"
    echo "    ver:tool \"${CHECK_TOOLS[$i]}\" ;"
    echo "    ver:exitCode ${CHECK_CODES[$i]} ;"
    echo "    ver:summary \"${CHECK_SUMMARIES[$i]}\" ;"
    echo "    ver:verifiedGraphHash \"$GRAPH_HASH\" ;"
    echo "    ver:recordedAt \"$RECORDED_AT\" ."
    echo
  done
} > evidence/ontology.ttl

echo "verify-evidence.sh: recorded ${#CHECK_NAMES[@]} checks -> evidence/ontology.ttl (graph hash binding: $GRAPH_HASH)"
for i in "${!CHECK_NAMES[@]}"; do
  echo "  ${CHECK_NAMES[$i]}: exit ${CHECK_CODES[$i]}"
done
exit 0
